mapper.select:
SELECT id, email, name, picture, account_token, created_at, updated_at
FROM users
WHERE email = #{email}

SELECT id, email, name, picture, account_token, created_at, updated_at
FROM users
WHERE account_token = #{accountToken}
   OR id IN (
       SELECT user_id
       FROM user_agent_tokens
       WHERE token = #{accountToken}
   )

mapper.update:
UPDATE users
SET account_token = #{accountToken}, updated_at = NOW()
WHERE email = #{email}

UPDATE users
SET name = #{name}, picture = #{picture}, updated_at = NOW()
WHERE email = #{email}
